// MEXC Futures symbols are formatted as BASE_USDT (e.g. BTC_USDT)
const tickers = $input.first().json.data || [];
const seen = new Set();
const items = [];
for (const t of tickers) {
  if (typeof t.symbol !== 'string' || !t.symbol.endsWith('_USDT')) continue;
  const sym = t.symbol.slice(0, -5); // strip '_USDT'
  if (!seen.has(sym) && /^[A-Z]{2,10}$/.test(sym)) {
    seen.add(sym);
    items.push({ json: { symbol: sym, mexcPrice: parseFloat(t.lastPrice) } });
  }
}
return items;

const jupItems = $input.all();
const tokenItems = $('Build MEXC Futures Map').all();

const mexcLookup = {};
for (const item of tokenItems) {
  mexcLookup[item.json.symbol] = item.json.mexcPrice;
}

const common = [];
const seenMints = new Set();

for (const jupItem of jupItems) {
  const r = jupItem.json;
  const sym = (r.symbol || '').toUpperCase();

  if (!mexcLookup[sym] || !r.id || seenMints.has(r.id)) continue;

  const mexcPrice = mexcLookup[sym];
  const jupPrice = parseFloat(r.usdPrice || 0);

  // Price sanity filter: within 5% to eliminate false symbol matches
  if (jupPrice <= 0 || Math.abs((mexcPrice - jupPrice) / jupPrice) > 0.05) continue;

  seenMints.add(r.id);

  const stats24h = r.stats24h || {};
  common.push({
    symbol: sym,
    mint: r.id,
    name: r.name || sym,
    decimals: r.decimals ?? null,
    mexc_price: mexcPrice,
    jup_price: jupPrice,
    jup_volume_24h: (stats24h.buyVolume || 0) + (stats24h.sellVolume || 0),
    jup_liquidity: r.liquidity || 0,
    tags: Array.isArray(r.tags) ? r.tags.join(',') : '',
    updated_at: new Date().toISOString()
  });
}

common.sort((a, b) => a.symbol.localeCompare(b.symbol));
console.log(`Found ${common.length} common futures tokens out of ${Object.keys(mexcLookup).length} MEXC futures symbols`);
return common.map(t => ({ json: t }));
